工厂模式
根据不同的需要，返回同一类的不同的对象

class User &#123;  static UserFactory(role) &#123;    switch(role) &#123;      case &#x27;superadmin&#x27;:         return new User(role, [&#x27;home&#x27;, &#x27;super&#x27;, &#x27;user&#x27;, &#x27;message&#x27;]);        break;      case &#x27;admin&#x27;:        return new User(role, [&#x27;home&#x27;, &#x27;user&#x27;, &#x27;message&#x27;]);        break;      case &#x27;editor&#x27;:        return new User(role, [&#x27;home&#x27;, &#x27;message&#x27;]);        break;      default:         throw new Error(&quot;参数错误&quot;);    &#125;  &#125;    constructor(role, pages) &#123;    this.role = role;    this.pages = pages;  &#125;&#125;



抽象工厂模式
抽象工厂不直接生成实例，而是用于创建类的模板

class User &#123;  constructor(name) &#123;    this.name = name;  &#125;    welcome() &#123;    console.log(&quot;欢迎回来&quot;, this.name);  &#125;    showData() &#123;    throw new Error(&quot;抽象方式需要被实现&quot;)  &#125;&#125;class SuperAdmin extends User &#123;   constructor(name) &#123;    this.name = name;    this.role = &#x27;superadmin&#x27;;    this.pages = [&#x27;home&#x27;, &#x27;super&#x27;, &#x27;user&#x27;, &#x27;message&#x27;];  &#125;    welcome() &#123;    console.log(&quot;欢迎回来&quot;, this.name);  &#125;    showData() &#123;    console.log(&quot;超级管理员才能看到的数据&quot;);  &#125;    addSuper() &#123;      &#125;    addUser() &#123;      &#125;    addMessage() &#123;      &#125;&#125;class Admin extends User &#123;   constructor(name) &#123;    this.name = name;    this.role = &#x27;admin&#x27;;    this.pages = [&#x27;home&#x27;, &#x27;user&#x27;, &#x27;message&#x27;];  &#125;    welcome() &#123;    console.log(&quot;欢迎回来&quot;, this.name);  &#125;    showData() &#123;    console.log(&quot;管理员看到的数据&quot;);  &#125;    addUser() &#123;      &#125;    addMessage() &#123;      &#125;&#125;class Editor extends User &#123;   constructor(name) &#123;    this.name = name;    this.role = &#x27;admin&#x27;;    this.pages = [&#x27;home&#x27;, &#x27;message&#x27;];  &#125;    welcome() &#123;    console.log(&quot;欢迎回来&quot;, this.name);  &#125;    showData() &#123;    console.log(&quot;编辑看到的数据&quot;);  &#125;    addMessage() &#123;      &#125;&#125;function getAbstractFactory(role) &#123;  switch(role) &#123;    case &#x27;superadmin&#x27;:      return SuperAdmin;      break;    case &#x27;admin&#x27;:      return Admin;      break;    case &#x27;editor&#x27;:      return Editor;      break;    default:      throw new Error(&quot;参数错误&quot;);  &#125;&#125;

