单例模式// es5 闭包实现const Singleton = (function() &#123;  let instance;    function User(name, age) &#123;    this.name = name;    this.age = age;  &#125;    return function(name, age) &#123;    if(!instance) &#123;      instance = new User(name, age);    &#125;    return instance;  &#125;&#125;)// es6 类实现class Singleton &#123;  constructor(name, age) &#123;    if(!Singleton.instance) &#123;      this.name = name;      this.age = age;      Singleton.instance = this;    &#125;        return Singleton.instance;  &#125;&#125;

装饰器模式
装饰器模式可以很方便得提高扩展性，axios的拦截器、react高阶组件就是典型的装饰器模式

Function.prototype.before = function(beforeFn) &#123;  const _this = this;  return function() &#123;    before.apply(this, arguments);    return _this.apply(this, arguments);  &#125;&#125;Function.prototype.after = function(beforeFn) &#123;  const _this = this;  return function() &#123;    const result = _this.apply(this, arguments);    before.apply(this, arguments);    return result;  &#125;&#125;function render() &#123;  &#125;function log() &#123;  &#125;render = render.before(log);



适配器模式
让不兼容的类可以工作

class Tencent &#123;  show() &#123;    // 渲染腾讯地图  &#125;&#125;class BaiDu &#123;  display() &#123;    // 渲染百度地图  &#125;&#125;// 腾讯地图的适配器class TencentAdapater extends Tencent &#123;  constructor() &#123;    super()  &#125;    display() &#123;		this.show();  &#125;&#125;function renderMap(map) &#123;  map.display();&#125;

策略模式
定义一系列算法，并将其封装起来，使得算法可以自由替换，并且避免大量的if else，常用的根据状态码来显示不同的内容就可以使用策略模式来简化代码

const strategry = &#123;  &quot;A&quot;: (salary) =&gt; &#123;    return salary * 4;  &#125;,  &quot;B&quot;: (salary) =&gt; &#123;    return salary * 3;  &#125;,  &quot;C&quot;: (salary) =&gt; &#123;    return salary * 2;  &#125;,&#125;function calBonus(level, salary) &#123;  return strategry[level](salary);&#125;

代理模式
为一个对象提供一系列操作方法来限制对他的访问，vue就是通过代理模式实现的响应式

const obj = &#123;  name: &#x27;neko&#x27;,  price: 10000&#125;;const proxy = new Proxy(obj, &#123;  get(target, key) &#123;    if(key == price) &#123;      console.log(&quot;访问&quot;);    &#125;        return target[key];  &#125;,    set(target, key, value) &#123;  	if(key === price) &#123;      console.log(&quot;设置了&quot;);      if(value &gt; 10000) &#123;        console.log(&quot;成交&quot;);        target[key] = value;      &#125; else &#123;        throw new Error(&quot;加钱！&quot;);      &#125;    &#125;  &#125;&#125;)

观察者模式
当一个对象更新后，所有依赖他的对象都被自动更新，vue中的watch就是观察者模式

// 被观察者更新后class Subject &#123;  constructor() &#123;    this.observers = [];  &#125;    add(observer) &#123;    this.observers.push(observer);  &#125;    remove(observer) &#123;    this.observers  = this.observers.filter(item =&gt; item !== observer);  &#125;  notify() &#123;    this.observers.forEach(item =&gt; &#123;      item.updata();    &#125;)  &#125;&#125;// 观察者自动更新class Observer &#123;  constructor(name) &#123;    this.name = name;  &#125;    updata() &#123;      &#125;&#125;

